Hello, welcome to this blog. Today, we’re going to learn how to use Sora Editor with TextMate in version 0.18.1.






TIP
Before you start, make sure you have prepared textmate themes and languages files. You may find them in TextMate.


Load Default Themestry &#123;
	FileProviderRegistry.getInstance().addFileProvider(new AssetsFileResolver(getAssets()));

    String[] themes &#x3D; &#123;&quot;quietlight&quot;, &quot;darcula&quot;&#125;;
    var themeRegistry &#x3D; ThemeRegistry.getInstance();

    int i &#x3D; themes.length;
    for (int j &#x3D; 0; j &lt; i; ) &#123;
    	String name &#x3D; themes[j];
        var path &#x3D; &quot;textmate&#x2F;&quot; + name + &quot;.json&quot;;
        themeRegistry.loadTheme(new ThemeModel(IThemeSource.fromInputStream(FileProviderRegistry.getInstance().tryGetInputStream(path), path, null), name));
        j++;

    &#125;
&#125; catch (Exception e) &#123;
	e.printStackTrace();
&#125;


Load Default LanguagesGrammarRegistry.getInstance().loadGrammars(&quot;textmate&#x2F;languages.json&quot;);


Load Default Languages DynamicallyIn this case, we load Java language as an example.
GrammarDefinition grammarDefinition &#x3D; new GrammarDefinition() &#123;
    @Override
    public String getName() &#123;
        return &quot;java&quot;;
    &#125;

    @Override
    public String getLanguageConfiguration() &#123;
        return &quot;textmate&#x2F;java&#x2F;language-configuration.json&quot;;
    &#125;

    @Override
    public String getScopeName() &#123;
        return &quot;source.java&quot;;
    &#125;

    @Override
    public IGrammarSource getGrammar() &#123;
        return new IGrammarSource() &#123;
            @Override
            public String getFilePath() &#123;
                return &quot;textmate&#x2F;java&#x2F;syntaxes&#x2F;java.tmLanguage.json&quot;;
            &#125;

            @Override
            public Reader getReader() throws IOException &#123;
                return null;
            &#125;
        &#125;;
    &#125;
&#125;;

GrammarRegistry.getInstance().loadGrammar(grammarDefinition);
GrammarRegistry.getInstance().loadLanguageAndLanguageConfiguration(grammarDefinition);


Ensure TextMate Themestry &#123;
    var editorColorScheme &#x3D; binding.editor.getColorScheme();
    if (!(editorColorScheme instanceof TextMateColorScheme)) &#123;
        editorColorScheme &#x3D; TextMateColorScheme.create(ThemeRegistry.getInstance());
        binding.editor.setColorScheme(editorColorScheme);
    &#125;
&#125; catch (Exception e) &#123;
    e.printStackTrace();
&#125;


Apply LanguagesTextMateLanguage language;
var editorLanguage &#x3D; binding.editor.getEditorLanguage();
if (editorLanguage instanceof TextMateLanguage) &#123;
	language &#x3D; (TextMateLanguage) editorLanguage;
    language.updateLanguage(&quot;source.java&quot;);
&#125; else &#123;
    language &#x3D; TextMateLanguage.create(&quot;source.java&quot;, true);
&#125;
binding.editor.setEditorLanguage(language);


Apply Themes (With DayNight theme detection)Use ThemeRegistry.getInstance().setTheme() to apply themes.
int nightModeFlags &#x3D; getResources().getConfiguration().uiMode &amp; Configuration.UI_MODE_NIGHT_MASK;
switch (nightModeFlags) &#123;
case Configuration.UI_MODE_NIGHT_YES:
    ThemeRegistry.getInstance().setTheme(&quot;darcula&quot;);
    break;

case Configuration.UI_MODE_NIGHT_NO:
    ThemeRegistry.getInstance().setTheme(&quot;quietlight&quot;);
    break;

case Configuration.UI_MODE_NIGHT_UNDEFINED:

    break;
&#125;


Full source codepublic class MainActivity extends AppCompatActivity &#123;
    ActivityTestBinding binding;
    @Override
    protected void onCreate(Bundle savedInstanceState) &#123;
        super.onCreate(savedInstanceState);
        binding &#x3D; ActivityTestBinding.inflate(getLayoutInflater());
        setContentView(binding.getRoot());

        loadDefaultThemes();
        loadDefaultLanguages();

        ensureTextmateTheme();

        applyThemes();
        applyLanguages();

    &#125;

    private void loadDefaultThemes() &#123;

        try &#123;
            FileProviderRegistry.getInstance().addFileProvider(new AssetsFileResolver(getAssets()));

            String[] themes &#x3D; &#123;
                &quot;quietlight&quot;,
                &quot;darcula&quot;
            &#125;;
            var themeRegistry &#x3D; ThemeRegistry.getInstance();

            int i &#x3D; themes.length;
            for (int j &#x3D; 0; j &lt; i;) &#123;
                String name &#x3D; themes[j];
                var path &#x3D; &quot;textmate&#x2F;&quot; + name + &quot;.json&quot;;
                themeRegistry.loadTheme(new ThemeModel(IThemeSource.fromInputStream(FileProviderRegistry.getInstance().tryGetInputStream(path), path, null), name));
                j++;

            &#125;
        &#125; catch (Exception e) &#123;
            e.printStackTrace();
        &#125;

    &#125;

    public void loadDefaultLanguages() &#123;
        GrammarRegistry.getInstance().loadGrammars(&quot;textmate&#x2F;languages.json&quot;);
    &#125;

    public void ensureTextmateTheme() &#123;
        try &#123;
            var editorColorScheme &#x3D; binding.editor.getColorScheme();
            if (!(editorColorScheme instanceof TextMateColorScheme)) &#123;
                editorColorScheme &#x3D; TextMateColorScheme.create(ThemeRegistry.getInstance());
                binding.editor.setColorScheme(editorColorScheme);
            &#125;
        &#125; catch (Exception e) &#123;
            e.printStackTrace();
        &#125;
    &#125;

    public void applyThemes() &#123;

        int nightModeFlags &#x3D; getResources().getConfiguration().uiMode &amp; Configuration.UI_MODE_NIGHT_MASK;
        switch (nightModeFlags) &#123;
        case Configuration.UI_MODE_NIGHT_YES:
            ThemeRegistry.getInstance().setTheme(&quot;darcula&quot;);
            break;

        case Configuration.UI_MODE_NIGHT_NO:
            ThemeRegistry.getInstance().setTheme(&quot;quietlight&quot;);
            break;
        &#125;

    &#125;

    public void applyLanguages() &#123;

        ensureTextmateTheme();

        TextMateLanguage language;
        var editorLanguage &#x3D; binding.editor.getEditorLanguage();
        if (editorLanguage instanceof TextMateLanguage) &#123;
            language &#x3D; (TextMateLanguage) editorLanguage;
            language.updateLanguage(&quot;source.java&quot;);
        &#125; else &#123;
            language &#x3D; TextMateLanguage.create(&quot;source.java&quot;, true);
        &#125;
        binding.editor.setEditorLanguage(language);

    &#125;
&#125;


That’s all. I hope this blog post would help you.

去年，我撰寫了一篇文章，介紹過 Eruda 網頁源始碼線上檢查器，教導大家直接透過瀏覽器書籤直以呼喚這個程式，當然，它也還有其他方式呼喚的，不過這裏不作講解了，因為這個並不是這篇文章的重點。重點是 Eruda 檢查器是透過使用動態載入的方式把 JavaScript 文件載入至網站。
它的程式是取決於這個函數作初始化： eruda.init();
當然，eruda 是物件，init() 是方法，而這個物件是未下定義的，因此進行初始化前，需要載入應要的 JavaScript 外部檔案。
https:&#x2F;&#x2F;cdn.jsdelivr.net&#x2F;npm&#x2F;eruda


靜態載入什麼是靜態載入？其實就是我們經常在 HTML 文件使用的 &lt;link&gt; 和 &lt;script&gt; 標示用以載入 CSS 和 JS 文件，就是直接把這件文件直接載入，在一般簡單普通的網站直接載入是沒問題的，但如果你想按情況而載入特定 CSS 或 JS 文件的話，靜態載入的方式並非你最好的首選。

動態載入與靜態載入不同，動態載入能夠處理按情況所需，而載入哪些文件至網站，要實現動態載入的話，不是在 HTML 文件動手，而是透過編寫 JavaScript 實現動態載入。

編碼示例我在網上找到一些動態載入的 JavaScript 編碼示例，有興趣可以看看以下文章瞭解更多。






參考資料：程式人生
本文簡單介紹動態載入、移除、替換js&#x2F;css檔案 。有時候我們在寫前端的時候，會有出現需要動態載入一些如css js 這樣能減輕使用者載入負擔，從而提高響應效率。


載入文件function loadFile(filename, filetype) &#123;
    if (filetype &#x3D;&#x3D; &quot;js&quot;) &#123;
        var fileref &#x3D; document.createElement(&#39;script&#39;);
        fileref.setAttribute(&quot;type&quot;, &quot;text&#x2F;javascript&quot;);
        fileref.setAttribute(&quot;src&quot;, filename);
    &#125; else if (filetype &#x3D;&#x3D; &quot;css&quot;) &#123;
        var fileref &#x3D; document.createElement(&quot;link&quot;);
        fileref.setAttribute(&quot;rel&quot;, &quot;stylesheet&quot;);
        fileref.setAttribute(&quot;type&quot;, &quot;text&#x2F;css&quot;);
        fileref.setAttribute(&quot;href&quot;, filename);
    &#125;
    if (typeof fileref !&#x3D; &quot;undefined&quot;)
        document.getElementsByTagName(&quot;head&quot;)[0].appendChild(fileref);
&#125;


刪除文件function removeFile(filename, filetype) &#123;
    var targetelement &#x3D; (filetype &#x3D;&#x3D; &quot;js&quot;)? &quot;script&quot;: (filetype &#x3D;&#x3D; &quot;css&quot;)? &quot;link&quot;: &quot;none&quot;;
    var targetattr &#x3D; (filetype &#x3D;&#x3D; &quot;js&quot;)?&quot;src&quot;: (filetype &#x3D;&#x3D; &quot;css&quot;)? &quot;href&quot;: &quot;none&quot;;
    var allsuspects &#x3D; document.getElementsByTagName(targetelement);
    for (var i &#x3D; allsuspects.length; i &gt;&#x3D; 0; i--) &#123;
        if (allsuspects[i] &amp;&amp; allsuspects[i].getAttribute(targetattr) !&#x3D; null &amp;&amp; allsuspects[i].getAttribute(targetattr).indexOf(filename)!&#x3D;-1)
            allsuspects[i].parentNode.removeChild(allsuspects[i]);
    &#125;
&#125;


調用函數示例有了這些編碼，我可以把明亮和黑暗主題語法高亮砍掉重練。







